const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const crypto = require('crypto');

const input = $input.first().json.body || {};

if (!input.request_id || !input.decision || !input.approver || !input.policy_id || !input.policy_version) {
  return [{ json: { status: 'error', message: 'Missing required fields: request_id, decision, approver, policy_id, policy_version' } }];
}

const validDecisions = ['approved', 'rejected'];
if (!validDecisions.includes(input.decision)) {
  return [{ json: { status: 'error', message: 'decision must be approved or rejected' } }];
}

const priorPolicy = (input.policy && typeof input.policy === 'object' && !Array.isArray(input.policy))
  ? input.policy
  : null;
const approval = (input.approval && typeof input.approval === 'object' && !Array.isArray(input.approval))
  ? input.approval
  : null;

if (!priorPolicy) {
  return [{ json: { status: 'error', message: 'policy object from the prior requires_approval response is required' } }];
}

if (!approval || !approval.token) {
  return [{ json: { status: 'error', message: 'approval.token from the prior policy response is required' } }];
}

const signingSecret = String($env.N8N_ENCRYPTION_KEY || '').trim();
if (!signingSecret) {
  return [{ json: { status: 'error', message: 'approval verification secret is not configured' } }];
}

const requestId = String(input.request_id).trim();
const policyId = String(input.policy_id).trim();
const policyVersion = String(input.policy_version).trim();
const decision = String(input.decision).trim();
const approver = String(input.approver).trim();
const endpoint = String(approval.endpoint || '').trim();
const method = String(approval.method || '').trim().toUpperCase();
const token = String(approval.token || '').trim();

let signedEnvelope;
try {
  const [encodedPayload, providedSignature] = token.split('.');
  if (!encodedPayload || !providedSignature) {
    throw new Error('malformed');
  }

  const serializedPayload = Buffer.from(encodedPayload, 'base64url').toString('utf8');
  const expectedSignature = crypto.createHmac('sha256', signingSecret).update(serializedPayload).digest('hex');
  const providedBuffer = Buffer.from(providedSignature, 'hex');
  const expectedBuffer = Buffer.from(expectedSignature, 'hex');

  if (providedBuffer.length !== expectedBuffer.length || !crypto.timingSafeEqual(providedBuffer, expectedBuffer)) {
    throw new Error('signature_mismatch');
  }

  signedEnvelope = JSON.parse(serializedPayload);
} catch (error) {
  return [{ json: { status: 'error', message: 'approval.token is invalid' } }];
}

const signedPolicy = (signedEnvelope.policy && typeof signedEnvelope.policy === 'object' && !Array.isArray(signedEnvelope.policy))
  ? signedEnvelope.policy
  : null;
const signedApproval = (signedEnvelope.approval && typeof signedEnvelope.approval === 'object' && !Array.isArray(signedEnvelope.approval))
  ? signedEnvelope.approval
  : null;

if (!signedPolicy || !signedApproval) {
  return [{ json: { status: 'error', message: 'approval.token is missing signed policy metadata' } }];
}

if (String(signedEnvelope.request_id || '').trim() !== requestId) {
  return [{ json: { status: 'error', message: 'request_id must match the signed approval token' } }];
}

if (String(signedPolicy.decision || '').trim() !== 'requires_approval') {
  return [{ json: { status: 'error', message: 'policy.decision must be requires_approval' } }];
}

if (String(signedPolicy.policy_id || '').trim() !== policyId || String(signedPolicy.policy_version || '').trim() !== policyVersion) {
  return [{ json: { status: 'error', message: 'policy_id and policy_version must match the signed approval token' } }];
}

if (String(priorPolicy.policy_id || '').trim() !== policyId || String(priorPolicy.policy_version || '').trim() !== policyVersion || String(priorPolicy.decision || '').trim() !== 'requires_approval') {
  return [{ json: { status: 'error', message: 'policy object must match the prior requires_approval response' } }];
}

if (endpoint !== String(signedApproval.endpoint || '').trim() || method !== String(signedApproval.method || '').trim().toUpperCase()) {
  return [{ json: { status: 'error', message: 'approval metadata must match the signed approval token' } }];
}

if (endpoint !== '/webhook/policy/approval' || method !== 'POST') {
  return [{ json: { status: 'error', message: 'approval metadata must come from the prior policy response' } }];
}

const auditDecision = decision === 'approved' ? 'allowed' : 'denied';
const policyReason = Array.isArray(signedPolicy.reasons) ? signedPolicy.reasons.join('; ') : null;
const riskScore = Number.isFinite(Number(signedPolicy.risk_score)) ? Math.round(Number(signedPolicy.risk_score)) : null;

return [{
  json: {
    request_id: requestId,
    decision,
    approver,
    comment: String(input.comment || ''),
    approved_at: new Date().toISOString(),
    policy_id: policyId,
    policy_version: policyVersion,
    policy: {
      ...signedPolicy,
      decision: 'requires_approval'
    },
    approval: {
      ...signedApproval,
      token
    },
    auditDecision,
    policy_reason: policyReason,
    risk_score: riskScore
  }
}];

